mapper.select:
SELECT id, parking_lot_id, name, rule_type, first_hour_fee, additional_hour_fee, 
       daily_max_fee, monthly_fee, start_time, end_time, is_default, status, created_at, updated_at
FROM fee_rule


        AND parking_lot_id = #{parkingLotId}


       AND rule_type = #{ruleType}


       AND status = #{status}
